    {'span_start': 415, 'span_end': 462, 'span_text': 'ثُمَّ جَعَلْنَاهُ نُطْفَةً فِي قَرَارٍ مَّكِينٍ'},
    {'span_start': 465, 'span_end': 674, 'span_text': 'ثُمَّ خَلَقْنَا النُّطْفَةَ عَلَقَةً فَخَلَقْنَا الْعَلَقَةَ مُضْغَةً فَخَلَقْنَا الْمُضْغَةَ عِظَامًا فَكَسَوْنَا الْعِظَامَ لَحْمًا ثُمَّ أَنشَأْنَاهُ خَلْقًا آخَرَ فَتَبَارَكَ اللَّهُ أَحْسَنُ الْخَالِقِينَ'},
    {'span_start': 750, 'span_end': 773, 'span_text': 'إن الله جميل يحب الجمال'},
    {'span_start': 1065, 'span_end': 1110, 'span_text': 'وَمَن يَتَّقِ اللَّهَ يَجْعَل لَّهُ مَخْرَجًا'},
    {'span_start': 1113, 'span_end': 1152, 'span_text': 'وَيَرْزُقْهُ مِنْ حَيْثُ لَا يَحْتَسِبُ'},
    {'span_start': 1224, 'span_end': 1288, 'span_text': 'إن الله لا ينظر إلى صوركم وأموالكم ولكن ينظر إلى قلوبكم وأعمالكم'}
]

citations = []
# Map spans to types and references
for idx, s in enumerate(processed_spans):
    is_hadith = idx in (3, 6)
    entry = {
        "span_start": s["span_start"],
        "span_end": s["span_end"],
        "span_text": s["span_text"],
        "citation_type": "Hadeeth" if is_hadith else "Aya",
        "is_valid": False,
        "aya_reference": {},
        "hadeeth_reference": {},
        "corrected_text": "خطأ",
        "completely_invalid": True
    }
    if not is_hadith:
        if idx in (0,1,2):
            # Surah Al-Mu'minun 23:12-14
            entry["aya_reference"] = {
                "sura_name": "المؤمنون",
                "sura_number": 23,
                "aya_number": 12 + idx
            }
        elif idx == 4:
            entry["aya_reference"] = {
                "sura_name": "الطلاق",
                "sura_number": 65,
                "aya_number": 2
            }
        elif idx == 5:
            entry["aya_reference"] = {
                "sura_name": "الطلاق",
                "sura_number": 65,
                "aya_number": 3
            }
    else:
        # We know it's in Sahih Muslim, but cannot provide precise numbers without the dataset
        pass
    
    citations.append(entry)

print(json.dumps({"citations": citations}, ensure_ascii=False, indent=2))
